          if val == &value {
              count += 1;
          }
      }
      count
  }

  fn count_iterator(map: &HashMap, value: Progress) -> usize {
      // map is a hashmap with String keys and Progress values.
      // map = { "variables1": Complete, "from_str": None, ... }
      map.values().filter(|&progress| *progress == value).count()
  }

  fn count_collection_for(collection: &[HashMap], value: Progress) -> usize {
      let mut count = 0;
      for map in collection {
          for val in map.values() {
              if val == &value {
                  count += 1;
              }
          }
      }
      count
  }

  fn count_collection_iterator(collection: &[HashMap], value: Progress) -> usize {
      // collection is a slice of hashmaps.
      // collection = [{ "variables1": Complete, "from_str": None, ... },
      //     { "variables2": Complete, ... }, ... ]
      collection.into_iter()
      .flat_map(|x| x.values())
      .filter(|&progress| *progress == value)
      .count()
  }

