/// Create a new task context with a trap return addr and a kernel stack pointer
pub fn goto_restore(kstack_ptr: usize) -> Self {
    extern "C" {
        fn __restore();
    }
    Self {
        ra: __restore as usize,
        sp: kstack_ptr,
        s: [0; 12],
    }
}

这里把 rs 赋为 __restore 的地址，sp 赋了内核栈的地址，
